+            let bytes = unsafe { CStr::from_ptr(name) }.to_bytes();
+            let head_end = nis_first_unescaped_dot(bytes).unwrap_or(bytes.len());
+            buf.extend_from_slice(&bytes[..head_end]);
+        }
+        buf.push(0);
+        buf.as_mut_ptr() as *mut c_char
+    })
+}
